+        // Find Sec-WebSocket-Key header
+        const key_header = "Sec-WebSocket-Key: ";
+        const key_start = std.mem.indexOf(u8, request, key_header) orelse return error.InvalidHandshake;
+        const key_value_start = key_start + key_header.len;
