+        while (total_read < payload.len) {
+            const read = self.stream.read(payload[total_read..]) catch break;
+            if (read == 0) break;
+            total_read += read;
+        }
+
+        // Unmask if needed
+        if (masked) {
+            for (payload, 0..) |*byte, i| {
+                byte.* ^= mask[i % 4];
