+        } else if (payload.len < 65536) {
+            header[1] = 126;
+            std.mem.writeInt(u16, header[2..4], @intCast(payload.len), .big);
+            header_len = 4;
+        } else {
+            header[1] = 127;
+            std.mem.writeInt(u64, header[2..10], payload.len, .big);
